@Entity
@Table(name = "users")
@Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder
public class User {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(nullable = false, length = 100)
    private String name;

    @Column(nullable = false, unique = true)
    private String email;

    @Column(nullable = false)
    private String password;

    @Column(name = "is_active")
    @Builder.Default
    private Boolean isActive = true;

    @Version
    private Long version;

    // Cascade justification: Order lifecycle is fully owned by User.
    // orphanRemoval: true because an Order without a User is invalid.
    // FetchType: LAZY (default) because orders are not always needed in-memory.
    @OneToMany(mappedBy = "user", cascade = CascadeType.ALL, orphanRemoval = true, fetch = FetchType.LAZY)
    @Builder.Default
    private Set<Order> orders = new HashSet<>();

    @CreationTimestamp
    @Column(name = "created_at", updatable = false)
    private LocalDateTime createdAt;

    @UpdateTimestamp
    @Column(name = "updated_at")
    private LocalDateTime updatedAt;
}

@Entity
public class User {
    @OneToMany(mappedBy = "user", cascade = CascadeType.ALL, orphanRemoval = true)
    // No justification. If an Order is referenced by Invoice, this deletes it when
    // it is removed from User.orders. Data corruption.
    private Set<Order> orders = new HashSet<>();
}

@Repository
public interface UserRepository extends JpaRepository<User, Long>,
        JpaSpecificationExecutor<User> {

    Optional<User> findByEmail(String email);

    boolean existsByEmail(String email);

    @Query("SELECT u FROM User u WHERE u.isActive = true")
    Page<User> findAllActive(Pageable pageable);

    @Query("SELECT u FROM User u JOIN FETCH u.roles WHERE u.id = :id")
    Optional<User> findByIdWithRoles(@Param("id") Long id);

    @Query("""
        SELECT u FROM User u
        WHERE (:name IS NULL OR LOWER(u.name) LIKE LOWER(CONCAT('%', :name, '%')))
        AND (:isActive IS NULL OR u.isActive = :isActive)
        """)
    Page<User> search(@Param("name") String name,
                      @Param("isActive") Boolean isActive,
                      Pageable pageable);

    @Query("SELECT new com.example.dto.UserListDto(u.id, u.name, u.email) FROM User u")
    Page<UserListDto> findAllAsDto(Pageable pageable);

    @Modifying
    @Transactional
    @Query("UPDATE User u SET u.isActive = false WHERE u.lastLoginAt &lt; :cutoff")
    int deactivateInactiveUsers(@Param("cutoff") LocalDateTime cutoff);
}

// DTO projection (read-only)
public interface UserListDto {
    Long getId();
    String getName();
    String getEmail();
}

@Service
@Transactional
public class UserService {

    private final UserRepository userRepository;

    @Transactional(readOnly = true)
    public UserResponse findById(Long id) {
        // readOnly=true: Hibernate skips dirty-check flush
        User user = userRepository.findByIdWithRoles(id)  // JOIN FETCH loads roles here
                .orElseThrow(() -> new NotFoundException("User " + id + " not found"));
        return mapToResponse(user);
    }

    @Transactional
    public UserResponse create(CreateUserRequest request) {
        // No readOnly: Hibernate tracks changes, flushes at transaction end
        User user = new User();
        user.setName(request.getName());
        user.setEmail(request.getEmail());
        user.setPassword(passwordEncoder.encode(request.getPassword()));

        userRepository.save(user);  // INSERT happens at transaction end
        return mapToResponse(user);
    }
}
